import { Command } from '@commander-js/extra-typings';
import { printTable, Table } from 'console-table-printer';
import { programWrapper } from "../cli-utils/program-wrapper.js";
import { getLogger } from "../../logger.js";
import { LunchMoneyApi } from "../../api.js";
import { amazonToLM } from "../../amazon/amazon-to-lm.js";
import { writeJson } from "../../utils/files.js";
// TODO testing, docs
const logger = getLogger();
async function writeJsonData(fileDir, fileName, data) {
    logger.info(`${fileDir}/${fileName}`);
    await writeJson(fileDir, fileName, data);
}
export const amazonToLMCommand = () => {
    const program = new Command();
    return program
        .command('amazon-to-lm <filePath>')
        .description('Parse Amazon orders CSV generated by Amazon order scraper, match to LM transactions and update them. Must provide path to CSV file.')
        .option('-s, --start <date>', 'Start date for transactions')
        .option('-e, --end <date>', 'End date for transactions')
        .option('-t, --add-tags <tag...>', 'Tags to add to matched LM transactions (space separated)', ['amazon-link'])
        .option('--exclude-tags <tag...>', 'Exclude LM transactions with these tags', [
        'amazon-link',
    ])
        .option('--write-files [directory]', 'Write order success/issue data to JSON files. You may specify a directory or files will be added in an .lm-tools-data directory.')
        .option('--dry-run', 'Output transaction info to console/json but do not actually make any updates.')
        .action(programWrapper(async (filePath, _opts, command) => {
        const opts = command.optsWithGlobals();
        const { verbose, apiKey, dryRun, addTags, excludeTags, writeFiles } = opts;
        if (verbose)
            logger.level = Infinity;
        const lm = new LunchMoneyApi(apiKey);
        const res = await amazonToLM(lm, {
            filePath,
            tags: addTags,
            excludeTags,
            startDate: opts.start,
            endDate: opts.end,
            dryRun,
        });
        if (!res)
            return;
        const jsonFolder = typeof writeFiles === 'string' ? writeFiles : `.lm-tools-data/amazon`;
        const { successes, errors, extraMatches, unmatched, rowsWithIssues } = res;
        if (rowsWithIssues.length) {
            logger.warn(`⚠️ ${rowsWithIssues.length} order rows could not be parsed: `);
            printTable(rowsWithIssues, {
                columns: [
                    { name: 'id' },
                    { name: 'date' },
                    { name: 'items', maxLen: 50 },
                    { name: 'total' },
                ],
            });
        }
        if (unmatched.length) {
            logger.warn(`⚠️ ${unmatched.length} orders were not able to be matched: `);
            printTable(unmatched, {
                enabledColumns: ['orderId', 'date', 'items', 'total'],
                columns: [
                    { name: 'date' },
                    { name: 'total' },
                    { name: 'orderId' },
                    { name: 'items', maxLen: 70 },
                ],
                rowSeparator: true,
            });
        }
        if (extraMatches.length) {
            logger.warn(`⚠️ ${extraMatches.length} orders had multiple potential LM transaction matches: `);
            printTable(extraMatches.map(({ data, matches }) => ({
                orderId: data.orderId,
                date: data.date,
                items: data.items,
                total: data.total,
                matches: matches
                    .map((m) => `id:${m.id}, date:${m.date}, amount:${m.amount}, payee: ${m.payee}`)
                    .join('\n'),
            })), {
                enabledColumns: ['orderId', 'date', 'items', 'total', 'matches'],
                columns: [
                    { name: 'date' },
                    { name: 'total' },
                    { name: 'orderId' },
                    { name: 'items', maxLen: 50 },
                    { name: 'matches', maxLen: 50 },
                ],
                rowSeparator: true,
            });
        }
        if (errors.length) {
            logger.warn(`⚠️ ${errors.length} orders had errors when updating LM transactions: `);
            const t = new Table({ rowSeparator: true });
            errors.forEach(({ amazon, lunchMoney, error }) => {
                t.addRow({
                    orderId: amazon.orderId,
                    date: amazon.date,
                    total: amazon.total,
                    lmId: lunchMoney.id,
                    error: error.message,
                });
            });
            t.printTable();
        }
        if (successes.length) {
            if (dryRun) {
                logger.info(`✅ ${successes.length} orders successfully matched. No updates were made to LM transactions because this was a dry run, but here is the matched data: `);
            }
            else {
                logger.info(`✅ ${successes.length} orders successfully matched and updated in LM: `);
            }
            const t = new Table({
                rowSeparator: true,
                columns: [
                    { name: 'orderId' },
                    { name: 'date' },
                    { name: 'total' },
                    { name: 'lmId' },
                    { name: 'payee', maxLen: 30 },
                ],
            });
            successes.forEach(({ amazon, lunchMoney }) => {
                t.addRow({
                    orderId: amazon.orderId,
                    date: amazon.date,
                    total: amazon.total,
                    lmId: lunchMoney.id,
                    payee: lunchMoney.payee,
                });
            });
            t.printTable();
        }
        if (writeFiles) {
            logger.info(`Writing files: `);
            if (rowsWithIssues.length)
                await writeJsonData(jsonFolder, `amazon-orders-issues.json`, rowsWithIssues);
            if (unmatched.length)
                await writeJsonData(jsonFolder, `amazon-unmatched.json`, unmatched);
            if (extraMatches.length)
                await writeJsonData(jsonFolder, `amazon-extra-matches.json`, extraMatches);
            if (errors.length)
                await writeJsonData(jsonFolder, `amazon-update-errors.json`, errors);
            if (successes.length)
                await writeJsonData(jsonFolder, `amazon-successes.json`, successes);
        }
    }));
};
